<template>
    <div id="app">
        <All v-if="DESIGN == 'all'" />
        <Lada v-if="DESIGN == 'lada'" />
        <VW v-if="DESIGN == 'vw'" />
        <Skoda v-if="DESIGN == 'skoda'" />
        <JLR v-if="DESIGN == 'jlr'" />
        <Kia v-if="DESIGN == 'kia'" />
        <Peugeot v-if="DESIGN == 'peugeot'" />
        <Geely v-if="DESIGN == 'geely'" />
        <Tank v-if="DESIGN == 'tank'" />
        <Omoda v-if="DESIGN == 'omoda'" />
        <Haval v-if="DESIGN == 'haval'" />
        <Tenet v-if="DESIGN == 'tenet'" />

        <Slider v-if="SLIDER" />
    </div>
</template>

<script>
import Axios from 'axios'

import Slider from './components/Slider.vue'

import All from './components/All.vue'
import Lada from './components/Lada.vue'
import VW from './components/VW.vue'
import Skoda from './components/Skoda.vue'
import JLR from './components/JLR.vue'
import Kia from './components/Kia.vue'
import Peugeot from './components/Peugeot.vue'
import Geely from './components/Geely.vue'
import Tank from './components/Tank.vue'
import Omoda from './components/Omoda.vue'
import Haval from './components/Haval.vue'
import Tenet from './components/Tenet.vue'

export default {
    name: 'App',
    components: {
        Slider,
        All,
        Lada,
        VW,
        Skoda,
        JLR,
        Kia,
        Peugeot,
        Geely,
        Tank,
        Omoda,
        Haval,
        Tenet
    },
    computed: {
        DESIGN() { return this.$store.state.design },
        SLIDER() { return ( this.$store.state.ADV ) ? true : false }
    },
    data() {
        return {
            pollInterval: null
        };
    },
    mounted: function() {
        let STATE = this.$store.state

        if ( STATE.timeout ) {
            this.pollInterval = setInterval( () => {
                Axios
                    .post(
                        'https://portal.yug-avto.ru/service/screens/api/get/', 
                        STATE._GET, 
                        {
                            headers: {
                                'Content-Type': 'application/x-www-form-urlencoded',
                                'Accept': 'application/json'
                            }
                        }
                    )
                    .then( (response) => { 
                        if (response.data.status == 'success') {
                            this.$store.commit('SET_DATA', {
                                managers: response.data.managers,
                                items: response.data.items
                            });
                        }
                    })
                    .catch( (error) => {
                        console.error('Polling error:', error);
                    });
            }, STATE.timeout*1000);
        }
    },
    beforeDestroy() {
        if (this.pollInterval) {
            clearInterval(this.pollInterval);
        }
    },
	methods: {

        FormatPhone( q ) {
			
			q = String(q).replace(/[^\d;]/g, '');
			return ( q.length >= 11 ) ? '+' + ((q[0]=='7')?q[0]:'7') + ' ' + q[1] + q[2] + q[3] + ' ' + q[4] + q[5] + q[6] + ' ' + q[7] + q[8] + ' ' + q[9] + q[10] : null;
		}
	}
}
</script>

